#include <stdio.h>
#include <stdlib.h>

int main() {
    int m, b;
    scanf("%d %d", &m, &b);

    int max_sum = 0;
    int x_zero = m * b;
    int y_zero = b;

    for (int i = 0; i <= b * m; i += m) {
        int x = i;
        int y = b - i / m;
        int s = ((1 + y) * y / 2) * (x + 1);
        s += ((1 + x) * x / 2) * (y + 1);
        if (s > max_sum) {
            max_sum = s;
        }
    }
    printf("%d\n", max_sum);
    return 0;
}
